import { createHmac, randomBytes, timingSafeEqual } from 'node:crypto';

// ── Configuration ───────────────────────────────────────────────────────────

function getEnvOrThrow(key: string): string {
	const val = process.env[key];
	if (!val) throw new Error(`Missing required env var: ${key}`);
	return val;
}

/** Derive a signing secret from ADMIN_PASSWORD (always available in production). */
function getSigningSecret(): string {
	const pw = process.env.ADMIN_PASSWORD || '';
	// Use HMAC of a fixed salt with the password as key to derive a stable secret
	return createHmac('sha256', pw).update('milestone-tracker-session-salt').digest('hex');
}

/** Parse comma-separated API_KEYS from .env */
function getApiKeys(): string[] {
	const raw = process.env.API_KEYS || '';
	return raw
		.split(',')
		.map((k) => k.trim())
		.filter(Boolean);
}

// ── Session Management (stateless signed tokens) ────────────────────────────
// Token format: `{randomHex}.{hmac-sha256-hex}`
// This is stateless — no server-side session store needed.

const SESSION_COOKIE_NAME = 'mt_session';
const SESSION_MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

export interface Session {
	token: string;
	signedToken: string;
	createdAt: number;
	maxAge: number;
}

/** Create a new signed session token. */
export function createSession(): Session {
	const token = randomBytes(32).toString('hex');
	const signature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');
	const signedToken = `${token}.${signature}`;
	return {
		token,
		signedToken,
		createdAt: Date.now(),
		maxAge: SESSION_MAX_AGE_MS
	};
}

/** Verify a signed session token. Returns true if valid and not expired. */
export function verifySession(signedToken: string, maxAge: number = SESSION_MAX_AGE_MS): boolean {
	const lastDot = signedToken.lastIndexOf('.');
	if (lastDot === -1) return false;

	const token = signedToken.substring(0, lastDot);
	const providedSignature = signedToken.substring(lastDot + 1);

	if (!token || !providedSignature) return false;

	const expectedSignature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');

	try {
		return timingSafeEqual(
			Buffer.from(providedSignature, 'hex'),
			Buffer.from(expectedSignature, 'hex')
		);
	} catch {
		return false;
	}
}

/** Destroy a session by returning a cookie that immediately expires. */
export function destroySessionCookie(): { name: string; value: string; options: SessionCookieOptions } {
	return {
		name: SESSION_COOKIE_NAME,
		value: '',
		options: {
			path: '/',
			httpOnly: true,
			secure: process.env.NODE_ENV === 'production',
			sameSite: 'lax',
			maxAge: 0
		}
	};
}

/** Build a Set-Cookie header value for a new session. */
export function buildSessionCookie(session: Session): string {
	const opts = sessionCookieOptions(session.maxAge);
	return `${SESSION_COOKIE_NAME}=${session.signedToken}; Path=${opts.path}; HttpOnly${opts.secure ? '; Secure' : ''}; SameSite=${opts.sameSite}; Max-Age=${Math.floor(opts.maxAge / 1000)}`;
}

// ── Bearer Token Validation ─────────────────────────────────────────────────

/** Validate a Bearer token against API_KEYS from .env. */
export function validateBearerToken(token: string): boolean {
	const apiKeys = getApiKeys();
	return apiKeys.some((key) => timingSafeEqual(Buffer.from(token), Buffer.from(key)));
}

// ── Cookie Helpers ──────────────────────────────────────────────────────────

export interface SessionCookieOptions {
	path: string;
	httpOnly: boolean;
	secure: boolean;
	sameSite: 'lax' | 'strict';
	maxAge: number; // seconds
}

function sessionCookieOptions(maxAgeMs: number): SessionCookieOptions {
	return {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(maxAgeMs / 1000)
	};
}

// ── Auth Middleware Logic ────────────────────────────────────────────────────
// Extracted as pure functions for testability. Used by hooks.server.ts.

export type AuthResult =
	| { authenticated: true; method: 'cookie' | 'bearer' }
	| { authenticated: false; reason: string };

/** Extract the signed session token from a Cookie header string. */
export function extractSessionCookie(cookieHeader: string | null): string | null {
	if (!cookieHeader) return null;
	const match = cookieHeader.match(/(?:^|;\s*)mt_session=([^;]+)/);
	return match ? match[1] : null;
}

/** Extract Bearer token from Authorization header. */
export function extractBearerToken(authHeader: string | null): string | null {
	if (!authHeader) return null;
	const parts = authHeader.split(' ');
	if (parts.length !== 2 || parts[0] !== 'Bearer') return null;
	return parts[1] || null;
}

/**
 * Check authentication from cookie and/or authorization headers.
 * Returns the auth result without performing any side effects.
 */
export function checkAuth(
	cookieHeader: string | null,
	authHeader: string | null
): AuthResult {
	// 1. Try Bearer token first (CLI/API usage)
	const bearer = extractBearerToken(authHeader);
	if (bearer) {
		if (validateBearerToken(bearer)) {
			return { authenticated: true, method: 'bearer' };
		}
		return { authenticated: false, reason: 'invalid_bearer_token' };
	}

	// 2. Try session cookie (Web usage)
	const sessionToken = extractSessionCookie(cookieHeader);
	if (sessionToken) {
		if (verifySession(sessionToken)) {
			return { authenticated: true, method: 'cookie' };
		}
		return { authenticated: false, reason: 'invalid_session' };
	}

	return { authenticated: false, reason: 'no_credentials' };
}

/** Validate a login password against ADMIN_PASSWORD env var. */
export function validatePassword(password: string): boolean {
	const adminPassword = process.env.ADMIN_PASSWORD;
	if (!adminPassword) return false;
	return timingSafeEqual(Buffer.from(password), Buffer.from(adminPassword));
}

// ── Exports for hooks ───────────────────────────────────────────────────────

export const AUTH_COOKIE_NAME = SESSION_COOKIE_NAME;

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { createSession, validatePassword, buildSessionCookie, AUTH_COOKIE_NAME } from '$lib/server/auth.js';
import { loginRequestSchema } from '$lib/schemas/auth.js';

export const POST: RequestHandler = async ({ request, cookies }) => {
	// 1. Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = loginRequestSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	// 2. Validate password
	if (!validatePassword(parsed.data.password)) {
		return json({ error: 'unauthorized', message: '密码错误' }, { status: 401 });
	}

	// 3. Create session
	const session = createSession();

	// 4. Set HttpOnly session cookie
	cookies.set(AUTH_COOKIE_NAME, session.signedToken, {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(session.maxAge / 1000)
	});

	// 5. Return success with token
	return json({ token: session.signedToken });
};

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { AUTH_COOKIE_NAME } from '$lib/server/auth.js';

export const POST: RequestHandler = async ({ cookies }) => {
	// Clear the session cookie
	cookies.delete(AUTH_COOKIE_NAME, { path: '/' });

	return json({ message: '已退出登录' });
};

import { redirect, json } from '@sveltejs/kit';
import type { Handle } from '@sveltejs/kit';
import { checkAuth } from '$lib/server/auth.js';

export const handle: Handle = async ({ event, resolve }) => {
	const { url, request, cookies } = event;
	const path = url.pathname;

	// Skip auth for static assets and prerendered pages
	if (path.startsWith('/_app/') || path.startsWith('/favicon')) {
		return resolve(event);
	}

	// Public routes — no auth required
	const publicRoutes = ['/login', '/api/auth/login', '/api/auth/logout'];
	if (publicRoutes.some((r) => path === r || path.startsWith(r + '/'))) {
		// If already authenticated and visiting /login, redirect to home
		if (path === '/login') {
			const cookieHeader = request.headers.get('cookie');
			const authHeader = request.headers.get('authorization');
			const result = checkAuth(cookieHeader, authHeader);
			if (result.authenticated) {
				throw redirect(302, '/');
			}
		}
		return resolve(event);
	}

	// ── API routes: require auth (cookie or bearer) ──
	if (path.startsWith('/api/')) {
		const cookieHeader = request.headers.get('cookie');
		const authHeader = request.headers.get('authorization');
		const result = checkAuth(cookieHeader, authHeader);

		if (!result.authenticated) {
			// Return 401 JSON for API routes
			return json(
				{
					error: 'unauthorized',
					message: result.reason === 'invalid_bearer_token' ? '无效的 API Key' : '请先登录'
				},
				{ status: 401 }
			);
		}

		// Attach auth method to locals for downstream use
		event.locals.authMethod = result.method;
		return resolve(event);
	}

	// ── Page routes: require cookie auth, redirect to /login ──
	const cookieHeader = request.headers.get('cookie');
	const authHeader = request.headers.get('authorization');
	const result = checkAuth(cookieHeader, authHeader);

	if (!result.authenticated) {
		throw redirect(302, '/login');
	}

	event.locals.authMethod = result.method;
	return resolve(event);
};

// See https://svelte.dev/docs/kit/types#app.d.ts
// for information about these interfaces
declare global {
	namespace App {
		// interface Error {}
		interface Locals {
			authMethod?: 'cookie' | 'bearer';
		}
		// interface PageData {}
		// interface PageState {}
		// interface Platform {}
	}
}

export {};

import { describe, it, expect, beforeEach, afterEach } from 'vitest';

// ── We test the pure auth functions directly (they're stateless, no DB needed) ──

// Must set env vars before importing the module (it reads at import time)
beforeEach(() => {
	process.env.ADMIN_PASSWORD = 'test_admin_password';
	process.env.API_KEYS = 'key_abc123,key_xyz789';
});

afterEach(() => {
	delete process.env.ADMIN_PASSWORD;
	delete process.env.API_KEYS;
});

const {
	createSession,
	verifySession,
	validateBearerToken,
	validatePassword,
	checkAuth,
	extractSessionCookie,
	extractBearerToken,
	destroySessionCookie,
	buildSessionCookie,
	AUTH_COOKIE_NAME
} = await import('./auth.js');

// ── Session Management ──────────────────────────────────────────────────────

describe('auth — session management', () => {
	it('creates a signed session with token and signature', () => {
		const session = createSession();
		expect(session.token).toBeDefined();
		expect(session.signedToken).toContain('.');
		expect(session.signedToken).toMatch(/^[a-f0-9]+\.[a-f0-9]+$/);
		expect(session.maxAge).toBe(24 * 60 * 60 * 1000);
	});

	it('verifies a valid signed token', () => {
		const session = createSession();
		expect(verifySession(session.signedToken)).toBe(true);
	});

	it('rejects tampered token', () => {
		const session = createSession();
		const tampered = session.signedToken.slice(0, -1) + '0';
		expect(verifySession(tampered)).toBe(false);
	});

	it('rejects token without dot separator', () => {
		expect(verifySession('nodothere')).toBe(false);
		expect(verifySession('')).toBe(false);
	});

	it('rejects empty string', () => {
		expect(verifySession('')).toBe(false);
	});

	it('rejects token with different secret (env changed)', () => {
		const session = createSession();
		process.env.ADMIN_PASSWORD = 'different_password';
		// Re-import to pick up new env — but since module caches, we test with original
		// The verifySession uses the same getSigningSecret() which reads env at call time
		expect(verifySession(session.signedToken)).toBe(false);
	});

	it('generates unique tokens on each call', () => {
		const s1 = createSession();
		const s2 = createSession();
		expect(s1.token).not.toBe(s2.token);
		expect(s1.signedToken).not.toBe(s2.signedToken);
	});

	it('buildSessionCookie returns a valid Set-Cookie string', () => {
		const session = createSession();
		const cookie = buildSessionCookie(session);
		expect(cookie).toContain('mt_session=');
		expect(cookie).toContain('Path=/');
		expect(cookie).toContain('HttpOnly');
		expect(cookie).toContain('SameSite=lax');
		expect(cookie).toContain('Max-Age=');
	});
});

// ── Session Destruction ─────────────────────────────────────────────────────

describe('auth — session destruction', () => {
	it('destroySessionCookie returns cookie with maxAge 0', () => {
		const cookie = destroySessionCookie();
		expect(cookie.name).toBe(AUTH_COOKIE_NAME);
		expect(cookie.value).toBe('');
		expect(cookie.options.maxAge).toBe(0);
		expect(cookie.options.httpOnly).toBe(true);
		expect(cookie.options.path).toBe('/');
	});
});

// ── Bearer Token ────────────────────────────────────────────────────────────

describe('auth — bearer token', () => {
	it('accepts a valid API key', () => {
		expect(validateBearerToken('key_abc123')).toBe(true);
		expect(validateBearerToken('key_xyz789')).toBe(true);
	});

	it('rejects an invalid API key', () => {
		expect(validateBearerToken('wrong_key')).toBe(false);
		expect(validateBearerToken('')).toBe(false);
	});

	it('handles empty API_KEYS env var', () => {
		process.env.API_KEYS = '';
		expect(validateBearerToken('key_abc123')).toBe(false);
	});

	it('handles missing API_KEYS env var', () => {
		delete process.env.API_KEYS;
		expect(validateBearerToken('key_abc123')).toBe(false);
	});
});

// ── Password Validation ─────────────────────────────────────────────────────

describe('auth — password validation', () => {
	it('accepts correct password', () => {
		expect(validatePassword('test_admin_password')).toBe(true);
	});

	it('rejects wrong password', () => {
		expect(validatePassword('wrong')).toBe(false);
	});

	it('rejects empty password', () => {
		expect(validatePassword('')).toBe(false);
	});

	it('returns false when ADMIN_PASSWORD is not set', () => {
		delete process.env.ADMIN_PASSWORD;
		expect(validatePassword('anything')).toBe(false);
	});
});

// ── Extract Helpers ─────────────────────────────────────────────────────────

describe('auth — extract helpers', () => {
	it('extracts session cookie from cookie header', () => {
		const cookie = 'mt_session=abc123.sig; other=val';
		expect(extractSessionCookie(cookie)).toBe('abc123.sig');
	});

	it('returns null when no mt_session cookie', () => {
		expect(extractSessionCookie('other=val')).toBeNull();
		expect(extractSessionCookie('')).toBeNull();
		expect(extractSessionCookie(null)).toBeNull();
	});

	it('extracts bearer token from Authorization header', () => {
		expect(extractBearerToken('Bearer key_abc123')).toBe('key_abc123');
	});

	it('returns null for malformed Authorization header', () => {
		expect(extractBearerToken('Basic abc')).toBeNull();
		expect(extractBearerToken('Bearer')).toBeNull();
		expect(extractBearerToken('Bearer ')).toBeNull();
		expect(extractBearerToken('')).toBeNull();
		expect(extractBearerToken(null)).toBeNull();
	});
});

// ── Check Auth (full middleware logic) ──────────────────────────────────────

describe('auth — checkAuth', () => {
	it('authenticates via valid bearer token', () => {
		const result = checkAuth(null, 'Bearer key_abc123');
		expect(result.authenticated).toBe(true);
		if (result.authenticated) {
			expect(result.method).toBe('bearer');
		}
	});

	it('rejects invalid bearer token', () => {
		const result = checkAuth(null, 'Bearer wrong_key');
		expect(result.authenticated).toBe(false);
		if (!result.authenticated) {
			expect(result.reason).toBe('invalid_bearer_token');
		}
	});

	it('authenticates via valid session cookie', () => {
		const session = createSession();
		const result = checkAuth(`mt_session=${session.signedToken}`, null);
		expect(result.authenticated).toBe(true);
		if (result.authenticated) {
			expect(result.method).toBe('cookie');
		}
	});

	it('rejects invalid session cookie', () => {
		const result = checkAuth('mt_session=invalid.token', null);
		expect(result.authenticated).toBe(false);
		if (!result.authenticated) {
			expect(result.reason).toBe('invalid_session');
		}
	});

	it('returns no_credentials when no auth provided', () => {
		const result = checkAuth(null, null);
		expect(result.authenticated).toBe(false);
		if (!result.authenticated) {
			expect(result.reason).toBe('no_credentials');
		}
	});

	it('prefers bearer token over cookie when both present', () => {
		const session = createSession();
		// Bearer is valid, so it should use bearer method
		const result = checkAuth(`mt_session=${session.signedToken}`, 'Bearer key_abc123');
		expect(result.authenticated).toBe(true);
		if (result.authenticated) {
			expect(result.method).toBe('bearer');
		}
	});

	it('rejects bearer token and falls through (does not try cookie)', () => {
		const session = createSession();
		// Invalid bearer — should NOT fall through to cookie
